Prob123_bugs_addsubz.error_msg:
module TopModule (
	input do_sub,
	input [7:0] a,
	input [7:0] b,
	output logic [7:0] out,
	output logic result_is_zero
);

	// Define the sum and difference variables
	logic signed [8:0] sum;
	logic signed [8:0] diff;

	// Calculate the sum and difference based on do_sub
	always @(*) begin
		if (do_sub) begin
			sum = a - b;
			diff = a - b;
		end else begin
			sum = a + b;
			diff = a + b;
		end
	end

	// Assign the output based on do_sub and the calculated values
	assign out = do_sub ? (diff < 0 ? -1 : diff) : sum;

	// Determine if the result is zero
	assign result_is_zero = (out == 0);

endmodule

Prob124_rule110.error_msg:
module TopModule (
    input  logic clk,
    input  logic load,
    input  logic [511:0] data,
    output logic [511:0] q
);

    logic [511:0] cells;

    initial begin
        cells = 0;
    end

    always @(posedge clk) begin
        if (load)
            cells = data;
        else begin
            for (int i = 0; i < 512; i++) begin
                int left = (i == 0) ? 0 : cells[(i-1)];
                int center = cells[i];
                int right = (i == 511) ? 0 : cells[(i+1)];
                q[i] = (left == 1 && center == 1 && right == 1) ? 0 :
                       (left == 1 && center == 1 && right == 0) ? 1 :
                       (left == 1 && center == 0 && right == 1) ? 1 :
                       (left == 1 && center == 0 && right == 0) ? 0 :
                       (left == 0 && center == 1 && right == 1) ? 1 :
                       (left == 0 && center == 1 && right == 0) ? 1 :
                       (left == 0 && center == 0 && right == 1) ? 1 :
                       (left == 0 && center == 0 && right == 0) ? 0 : 0;
            end
        end
    end

endmodule

Prob125_kmap3.error_msg:
module TopModule (
	input logic clk,
	input logic a,
	input logic b,
	input logic c,
	input logic d,
	output logic out
);

	// Initialize out to 0 for combinational logic
	initial begin
		out = 0;
	end

	// Derive the Boolean expression from the Karnaugh map:
	// out = a'b'd + a'c'd + a'b'c + a'b'c'd' + a'bc'd'
	assign out = (~a & ~b & d) | (~a & c & d) | (~a & ~b & c) | (~a & ~b & ~c & d) | (~a & b & ~c & d);

endmodule;

