            end
            WALK_RIGHT: begin
                if (bump == 2'b11 || bump_right)
                    next_state = WALK_LEFT;
            end
            default: next_state = WALK_LEFT;
        endcase
    end

    // Output logic
    always_comb begin
        walk_left = (current_state == WALK_LEFT);
        walk_right = (current_state == WALK_RIGHT);
    end

